============================================================================ */  
function canon(s){  
  s = String(s || "").toLowerCase().replace(/[^\x20-\x7e]/g, " "); // drop non-ASCII  
  s = s.replace(/[^a-z0-9\s]/g, " ");                               // keep a-z 0-9 space  
  s = s.replace(/\s+/g, " ").trim();  
  return s;  
}  
